Code.Terraform:
```hcl
# 创建两个位于不同可用区的子网，以便 VPC 跨越多个可用区
resource "aws_subnet" "subnet_a" {
  vpc_id            = "<example_resource_id>"
  cidr_block        = "10.0.0.0/24"
  availability_zone = "<example_az_1>" # 关键：第一个可用区
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = "<example_resource_id>"
  cidr_block        = "10.0.1.0/24"
  availability_zone = "<example_az_2>" # 关键：第二个可用区；确保子网位于多个可用区中
}
```
